import AdInstance from '../../sdk/adInstance'

const defaultRespond = {
    instanceId: '',
}

class MsGamesAdInstance extends AdInstance {
    private sdk: typeof $msstart
    private type: string
    private response: $msstart.AdInstance

    private loadAdsPromise: Promise<void> | null = null
    private showAdsPromise: Promise<void> | null = null
    private isLoadingTimedOut = false
    private isShowAdsResolved = true

    constructor(type: string, sdk: typeof $msstart) {
        super()
        this.sdk = sdk
        this.type = type
        this.response = defaultRespond
    }

    public getPlacementID(): string {
        return this.response.instanceId
    }

    public loadAsync(): Promise<void> {
        if (this.isLoadingTimedOut) {
            return Promise.reject(new Error('Loading ads is currently timed out.'))
        }

        if (this.loadAdsPromise) {
            return this.loadAdsPromise
        }

        const { Valid: V } = GameCore.Utils

        this.loadAdsPromise = new Promise<void>((resolve, reject) => {
            if (this.response && this.response.instanceId !== defaultRespond.instanceId) {
                resolve()
            }

            let promise: Promise<$msstart.AdInstance | void> = Promise.reject(
                new Error('Starting Point')
            )
            let totalLoadAdsAttempts = 1
            this.isLoadingTimedOut = false

            if (V.isNumber(window.$msstart.loadAdsRetryCount)) {
                const { loadAdsRetryCount } = window.$msstart

                if (loadAdsRetryCount > 0) {
                    totalLoadAdsAttempts += loadAdsRetryCount
                }
            }

            for (let i = 0; i < totalLoadAdsAttempts; i++) {
                promise = promise.catch(async (error) => {
                    if (error.message === 'Request Throttled Error') {
                        // ? Loop this error to immediately end the promise chain
                        return Promise.reject(new Error('Request Throttled Error'))
                    }

                    // ? Handle Request Throttled Error Case
                    if (this.isAdsLoadingTimedOutError(error)) {
                        const loadingTimeoutDuration = this.getLoadingTimeoutDuration(error)

                        if (loadingTimeoutDuration > 0) {
                            this.isLoadingTimedOut = true

                            // ? Retry loading when the timeout is over
                            setTimeout(() => {
                                this.isLoadingTimedOut = false
                                this.loadAsync()
                            }, loadingTimeoutDuration * 1000)

                            return Promise.reject(new Error('Request Throttled Error'))
                        }
                    }

                    return this.sdk.loadAdsAsync({
                        isRewardedAd: this.type === 'rewarded',
                        canBackfill: true,
                    })
                })
            }

            promise = promise
                .then((instance) => {
                    if (!instance) {
                        reject(new Error('Ad is not loaded. Instance is empty'))
                        return
                    }

                    this.response = instance
                    resolve()
                })
                .catch((error) => {
                    if (this.isAdsAlreadyLoadedError(error)) {
                        resolve()
                        return
                    }

                    reject(error)
                })
        }).finally(() => {
            this.loadAdsPromise = null
        })

        return this.loadAdsPromise
    }

    private isAdsAlreadyLoadedError(error: Error): boolean {
        let errorAsString = ''

        try {
            errorAsString = JSON.stringify(error)
        } catch (error) {
            return false
        }

        const isClientError = errorAsString.includes('LOAD_ADS_CLIENT_FAILURE')
        const isAlreadyLoadedError = errorAsString.includes('Ads already loaded.')
        return isClientError && isAlreadyLoadedError
    }

    private isAdsLoadingTimedOutError(error: Error): boolean {
        let errorAsString = ''

        try {
            errorAsString = JSON.stringify(error)
        } catch (error) {
            return false
        }

        const isRequestThrottled = errorAsString.includes('REQUEST_THROTTLED')
        return isRequestThrottled
    }

    private getLoadingTimeoutDuration(error: Error): number {
        let errorAsString = ''

        try {
            errorAsString = JSON.stringify(error)
        } catch (error) {
            return 0
        }

        const errorAsJSON = JSON.parse(errorAsString)

        if (!errorAsJSON.extra) {
            return 0
        }

        const { extra } = errorAsJSON

        if (!extra.timeLeft) {
            return 0
        }

        return extra.timeLeft as number
    }

    public async showAsync(): Promise<void> {
        let showAdsCompletedPromise: Promise<$msstart.AdInstance> | null = null

        const timeoutPromise = new Promise<void>((resolve, reject) => {
            setTimeout(() => {
                if (showAdsCompletedPromise) {
                    resolve()
                } else {
                    reject(new Error('Show ads is timed out'))
                }
            }, 15000)
        })

        const adPromise = new Promise<void>((resolve, reject) => {
            if (!this.response.instanceId) {
                reject(new Error('Ad is not loaded. InstanceId is empty'))
                return
            }

            if (this.showAdsPromise && !this.isShowAdsResolved) {
                reject(new Error('Show ads is already in progress'))
                return
            }

            this.isShowAdsResolved = false

            this.showAdsPromise = this.sdk
                .showAdsAsync(this.response.instanceId)
                .then((instance) => {
                    if (!instance.showAdsCompletedAsync) {
                        reject(new Error('Ad is not loaded. showAdsCompletedAsync is empty'))
                        return
                    }

                    showAdsCompletedPromise = instance.showAdsCompletedAsync

                    instance.showAdsCompletedAsync
                        .then(() => {
                            this.response = defaultRespond
                            resolve()
                        })
                        .catch((error) => {
                            //? handle user skip ads
                            // {
                            //     "code": "SHOW_ADS_COMPLETED_FAILURE",
                            //     "description": "User closed rewarded ad before completion."
                            // }
                            if (error.code && error.code === 'SHOW_ADS_COMPLETED_FAILURE') {
                                error.code = 'USER_INPUT'
                            }
                            reject(error)
                        })
                })
                .catch((error) => {
                    reject(error)
                })
                .finally(() => {
                    this.showAdsPromise = null
                    this.isShowAdsResolved = true
                })
        })

        return new Promise<void>((resolve, reject) => {
            Promise.all([timeoutPromise, adPromise])
                .then(() => {
                    resolve()
                })
                .catch((error) => {
                    reject(error)
                })
        })
    }
}

export default MsGamesAdInstance
